mkdir -p /var/www/html /var/log/nginx
printf 'Welcome to the benchmark webserver\n' > /var/www/html/index.html
printf 'Page not found - Please check your URL\n' > /var/www/html/404.html

cat > /etc/nginx/conf.d/benchmark-site.conf <<'EOF'
server {
    listen 8080;
    server_name _;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark;
    error_log  /var/log/nginx/benchmark-error.log;

    location / {
        limit_req zone=benchmark_limit burst=10;
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        internal;
    }
}
EOF

rm -f /etc/nginx/sites-enabled/default
nginx -t 2>&1

